<span class="line"><span style="color:#CDD6F4;">desc </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> find_tool</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;unknown&quot;</span><span style="color:#9399B2;">)</span></span>
